public class TestLifecycle {
    static java.util.List<String> log = new java.util.ArrayList<>();
    // Simulating @BeforeEach, @Test, @AfterEach lifecycle
    static void beforeEach() { log.add("before"); }
    static void afterEach() { log.add("after"); }
    static void runTest(Runnable test) {
        beforeEach();
        try { test.run(); log.add("test ok"); }
        catch (Throwable t) { log.add("test fail"); }
        afterEach();
    }
    public static void main(String[] args) {
        runTest(() -> { int x = 1 + 1; });
        runTest(() -> { throw new RuntimeException(); });
        System.out.println(log);
    }
}
